import React, { useState, useEffect } from 'react';
import { api } from '../services/api';

interface User {
  id: number;
  nombre: string;
  email: string;
  rol: string;
  activo: number;
  created_at: string;
  actividad_reciente: number;
}

interface UserStats {
  total_usuarios: number;
  usuarios_activos: number;
  administradores: number;
  veterinarios: number;
  tecnicos: number;
}

const UserManagement: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'users' | 'roles' | 'audit' | 'profile'>('users');
  const [users, setUsers] = useState<User[]>([]);
  const [stats, setStats] = useState<UserStats | null>(null);
  const [showUserForm, setShowUserForm] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(false);

  const [userForm, setUserForm] = useState({
    nombre: '',
    email: '',
    password: '',
    rol: 'tecnico'
  });

  useEffect(() => {
    if (activeTab === 'users') {
      loadUsers();
      loadStats();
    }
  }, [activeTab]);

  const loadUsers = async () => {
    setLoading(true);
    try {
      const response = await api.get('/users');
      setUsers(response.data);
    } catch (error) {
      console.error('Error cargando usuarios:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadStats = async () => {
    try {
      const response = await api.get('/users/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Error cargando estadísticas:', error);
    }
  };

  const createUser = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/users', userForm);
      setUserForm({ nombre: '', email: '', password: '', rol: 'tecnico' });
      setShowUserForm(false);
      loadUsers();
    } catch (error) {
      console.error('Error creando usuario:', error);
    }
  };

  const updateUser = async (user: User) => {
    try {
      await api.put(`/users/${user.id}`, {
        nombre: user.nombre,
        email: user.email,
        rol: user.rol,
        activo: user.activo
      });
      loadUsers();
    } catch (error) {
      console.error('Error actualizando usuario:', error);
    }
  };

  const getRoleColor = (rol: string) => {
    const colors = {
      administrador: '#e74c3c',
      gerente: '#f39c12',
      veterinario: '#3498db',
      tecnico: '#27ae60',
      auxiliar: '#95a5a6'
    };
    return colors[rol as keyof typeof colors] || '#6c757d';
  };

  const getRoleIcon = (rol: string) => {
    const icons = {
      administrador: '👑',
      gerente: '📊',
      veterinario: '🩺',
      tecnico: '🔧',
      auxiliar: '👤'
    };
    return icons[rol as keyof typeof icons] || '👤';
  };

  const renderUsers = () => (
    <div className="users-section">
      {/* Estadísticas */}
      {stats && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '30px' }}>
          <div className="stat-card" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', padding: '20px', borderRadius: '12px' }}>
            <div style={{ fontSize: '32px', fontWeight: 'bold' }}>{stats.total_usuarios}</div>
            <div style={{ opacity: 0.9 }}>Total Usuarios</div>
          </div>
          <div className="stat-card" style={{ background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)', color: 'white', padding: '20px', borderRadius: '12px' }}>
            <div style={{ fontSize: '32px', fontWeight: 'bold' }}>{stats.usuarios_activos}</div>
            <div style={{ opacity: 0.9 }}>Usuarios Activos</div>
          </div>
          <div className="stat-card" style={{ background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)', color: 'white', padding: '20px', borderRadius: '12px' }}>
            <div style={{ fontSize: '32px', fontWeight: 'bold' }}>{stats.administradores}</div>
            <div style={{ opacity: 0.9 }}>Administradores</div>
          </div>
          <div className="stat-card" style={{ background: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)', color: 'white', padding: '20px', borderRadius: '12px' }}>
            <div style={{ fontSize: '32px', fontWeight: 'bold' }}>{stats.veterinarios}</div>
            <div style={{ opacity: 0.9 }}>Veterinarios</div>
          </div>
        </div>
      )}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
        <h3 style={{ margin: 0, fontSize: '24px', color: '#2c3e50' }}>👥 Gestión de Usuarios</h3>
        <button 
          onClick={() => setShowUserForm(true)}
          style={{ 
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            color: 'white', 
            border: 'none', 
            padding: '12px 24px',
            borderRadius: '8px',
            fontWeight: '600',
            cursor: 'pointer',
            boxShadow: '0 4px 15px rgba(102, 126, 234, 0.3)'
          }}
        >
          ➕ Nuevo Usuario
        </button>
      </div>

      {showUserForm && (
        <div className="card" style={{ marginBottom: '25px', borderRadius: '12px', boxShadow: '0 8px 25px rgba(0,0,0,0.1)' }}>
          <div className="card-header" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', padding: '20px' }}>
            <h4 style={{ margin: 0 }}>➕ Crear Nuevo Usuario</h4>
          </div>
          <form onSubmit={createUser} style={{ padding: '25px' }}>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' }}>
              <div className="form-group">
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Nombre Completo</label>
                <input
                  type="text"
                  value={userForm.nombre}
                  onChange={(e) => setUserForm({...userForm, nombre: e.target.value})}
                  style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px', fontSize: '16px' }}
                  required
                />
              </div>
              <div className="form-group">
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Email</label>
                <input
                  type="email"
                  value={userForm.email}
                  onChange={(e) => setUserForm({...userForm, email: e.target.value})}
                  style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px', fontSize: '16px' }}
                  required
                />
              </div>
              <div className="form-group">
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Contraseña</label>
                <input
                  type="password"
                  value={userForm.password}
                  onChange={(e) => setUserForm({...userForm, password: e.target.value})}
                  style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px', fontSize: '16px' }}
                  required
                />
              </div>
              <div className="form-group">
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Rol</label>
                <select
                  value={userForm.rol}
                  onChange={(e) => setUserForm({...userForm, rol: e.target.value})}
                  style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px', fontSize: '16px' }}
                >
                  <option value="auxiliar">👤 Auxiliar</option>
                  <option value="tecnico">🔧 Técnico</option>
                  <option value="veterinario">🩺 Veterinario</option>
                  <option value="gerente">📊 Gerente</option>
                  <option value="administrador">👑 Administrador</option>
                </select>
              </div>
            </div>
            <div style={{ marginTop: '25px', display: 'flex', gap: '12px' }}>
              <button type="submit" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '8px', fontWeight: '600', cursor: 'pointer' }}>
                💾 Crear Usuario
              </button>
              <button type="button" onClick={() => setShowUserForm(false)} style={{ background: '#6c757d', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '8px', fontWeight: '600', cursor: 'pointer' }}>
                ❌ Cancelar
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="card" style={{ borderRadius: '12px', boxShadow: '0 8px 25px rgba(0,0,0,0.1)' }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: '#f8f9fa' }}>
                <th style={{ padding: '15px', textAlign: 'left', fontWeight: '600', color: '#2c3e50' }}>Usuario</th>
                <th style={{ padding: '15px', textAlign: 'left', fontWeight: '600', color: '#2c3e50' }}>Rol</th>
                <th style={{ padding: '15px', textAlign: 'left', fontWeight: '600', color: '#2c3e50' }}>Estado</th>
                <th style={{ padding: '15px', textAlign: 'left', fontWeight: '600', color: '#2c3e50' }}>Registro</th>
                <th style={{ padding: '15px', textAlign: 'left', fontWeight: '600', color: '#2c3e50' }}>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {users.map(user => (
                <tr key={user.id} style={{ borderBottom: '1px solid #e9ecef' }}>
                  <td style={{ padding: '15px' }}>
                    <div>
                      <div style={{ fontWeight: '600', color: '#2c3e50' }}>{user.nombre}</div>
                      <div style={{ fontSize: '14px', color: '#6c757d' }}>{user.email}</div>
                    </div>
                  </td>
                  <td style={{ padding: '15px' }}>
                    <span style={{
                      background: getRoleColor(user.rol),
                      color: 'white',
                      padding: '6px 12px',
                      borderRadius: '20px',
                      fontSize: '12px',
                      fontWeight: '600',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: '4px'
                    }}>
                      {getRoleIcon(user.rol)} {user.rol.toUpperCase()}
                    </span>
                  </td>
                  <td style={{ padding: '15px' }}>
                    <span style={{
                      background: user.activo ? '#d4edda' : '#f8d7da',
                      color: user.activo ? '#155724' : '#721c24',
                      padding: '6px 12px',
                      borderRadius: '20px',
                      fontSize: '12px',
                      fontWeight: '600'
                    }}>
                      {user.activo ? '✅ ACTIVO' : '❌ INACTIVO'}
                    </span>
                  </td>
                  <td style={{ padding: '15px', fontSize: '14px', color: '#6c757d' }}>
                    {new Date(user.created_at).toLocaleDateString()}
                  </td>
                  <td style={{ padding: '15px' }}>
                    <button 
                      onClick={() => setEditingUser(user)}
                      style={{ background: '#007bff', color: 'white', border: 'none', padding: '6px 12px', borderRadius: '6px', fontSize: '12px', cursor: 'pointer', marginRight: '8px' }}
                    >
                      ✏️ Editar
                    </button>
                    <button 
                      onClick={() => updateUser({...user, activo: user.activo ? 0 : 1})}
                      style={{ background: user.activo ? '#dc3545' : '#28a745', color: 'white', border: 'none', padding: '6px 12px', borderRadius: '6px', fontSize: '12px', cursor: 'pointer' }}
                    >
                      {user.activo ? '🚫 Desactivar' : '✅ Activar'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="profile-section">
      <div className="card" style={{ borderRadius: '12px', boxShadow: '0 8px 25px rgba(0,0,0,0.1)' }}>
        <div className="card-header" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', padding: '25px' }}>
          <h3 style={{ margin: 0, fontSize: '24px' }}>👤 Mi Perfil</h3>
        </div>
        <div style={{ padding: '30px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '30px' }}>
            <div>
              <h4 style={{ color: '#2c3e50', marginBottom: '20px' }}>Información Personal</h4>
              <div className="form-group" style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Nombre</label>
                <input type="text" defaultValue="Administrador" style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px' }} />
              </div>
              <div className="form-group" style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Email</label>
                <input type="email" defaultValue="admin@granja.com" style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px' }} />
              </div>
            </div>
            <div>
              <h4 style={{ color: '#2c3e50', marginBottom: '20px' }}>Cambiar Contraseña</h4>
              <div className="form-group" style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Contraseña Actual</label>
                <input type="password" style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px' }} />
              </div>
              <div className="form-group" style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>Nueva Contraseña</label>
                <input type="password" style={{ width: '100%', padding: '12px', border: '2px solid #e1e8ed', borderRadius: '8px' }} />
              </div>
            </div>
          </div>
          <button style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '8px', fontWeight: '600', cursor: 'pointer' }}>
            💾 Guardar Cambios
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="fade-in" style={{ padding: '20px', maxWidth: '1400px', margin: '0 auto' }}>
      <div className="card-header" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', borderRadius: '12px 12px 0 0', padding: '25px' }}>
        <div>
          <h1 className="card-title" style={{ fontSize: '28px', fontWeight: '700', margin: '0 0 8px 0' }}>👥 Administración de Usuarios</h1>
          <p style={{ margin: 0, opacity: 0.9, fontSize: '16px' }}>Gestión completa de usuarios, roles y permisos del sistema</p>
        </div>
      </div>

      <div className="card" style={{ borderRadius: '0 0 12px 12px', boxShadow: '0 10px 30px rgba(0,0,0,0.1)' }}>
        <div style={{ padding: '25px' }}>
          <div className="tab-container" style={{ marginBottom: '25px' }}>
            {[
              { key: 'users', label: '👥 Usuarios', desc: 'Gestionar usuarios' },
              { key: 'roles', label: '🔐 Roles', desc: 'Configurar permisos' },
              { key: 'audit', label: '📋 Auditoría', desc: 'Logs del sistema' },
              { key: 'profile', label: '👤 Mi Perfil', desc: 'Configuración personal' }
            ].map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key as any)}
                className={`tab-button ${activeTab === tab.key ? 'active' : ''}`}
                style={{
                  padding: '15px 20px',
                  margin: '0 8px 8px 0',
                  border: 'none',
                  borderRadius: '10px',
                  backgroundColor: activeTab === tab.key ? '#667eea' : '#f8f9fa',
                  color: activeTab === tab.key ? 'white' : '#495057',
                  cursor: 'pointer',
                  transition: 'all 0.3s ease',
                  fontWeight: '600',
                  boxShadow: activeTab === tab.key ? '0 4px 15px rgba(102, 126, 234, 0.3)' : '0 2px 8px rgba(0,0,0,0.1)',
                  transform: activeTab === tab.key ? 'translateY(-2px)' : 'none'
                }}
              >
                <div>{tab.label}</div>
                <div style={{ fontSize: '12px', opacity: 0.8, marginTop: '2px' }}>{tab.desc}</div>
              </button>
            ))}
          </div>

          {loading && (
            <div style={{ textAlign: 'center', padding: '40px' }}>
              <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔄</div>
              <div style={{ fontSize: '18px', color: '#667eea' }}>Cargando información...</div>
            </div>
          )}

          {activeTab === 'users' && renderUsers()}
          {activeTab === 'profile' && renderProfile()}
          {activeTab === 'roles' && (
            <div className="empty-state" style={{ textAlign: 'center', padding: '60px 20px' }}>
              <div style={{ fontSize: '64px', marginBottom: '16px' }}>🔐</div>
              <h3 style={{ color: '#495057', marginBottom: '8px' }}>Gestión de Roles</h3>
              <p style={{ color: '#6c757d' }}>Configuración avanzada de roles y permisos</p>
            </div>
          )}
          {activeTab === 'audit' && (
            <div className="empty-state" style={{ textAlign: 'center', padding: '60px 20px' }}>
              <div style={{ fontSize: '64px', marginBottom: '16px' }}>📋</div>
              <h3 style={{ color: '#495057', marginBottom: '8px' }}>Logs de Auditoría</h3>
              <p style={{ color: '#6c757d' }}>Registro completo de actividades del sistema</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default UserManagement;
